// ============================================================
// FILTROS DE CALIDAD + DEDUPLICACION
// ============================================================
const minReviews = $('Config').first().json.minReviews;

const socialDomains = [
  'facebook.com', 'fb.com',
  'instagram.com',
  'twitter.com', 'x.com',
  'linktr.ee',
  'wa.me', 'whatsapp.com',
  'youtube.com',
  'tiktok.com'
];

const seen = new Set();
const results = [];

for (const item of items) {
  const p = item.json;
  const query = p.query || '';
  const categoria = query.split(' en ')[0].trim() || 'sin categoría';

  // -- Filtro 1: Minimo de reseñas --
  const reviewCount = p.userRatingCount || 0;
  if (reviewCount < minReviews) continue;

  // -- Filtro 2: Sin web real --
  const website = (p.websiteUri || '').trim();
  const hasRealWebsite = website !== '' && !socialDomains.some(d => website.toLowerCase().includes(d));
  if (hasRealWebsite) continue;

  // -- Deduplicacion por googleMapsUri --
  const mapsUrl = p.googleMapsUri || '';
  if (mapsUrl && seen.has(mapsUrl)) continue;
  if (mapsUrl) seen.add(mapsUrl);

  results.push({
    json: {
      categoria:    categoria,
      nombre:       p.displayName?.text || '',
      rating:       p.rating || 0,
      reseñas:      reviewCount,
      telefono:     p.nationalPhoneNumber || '',
      direccion:    p.formattedAddress || '',
      web_actual:   website || '(sin web)',
      google_maps:  mapsUrl,
      fecha_scrape: new Date().toLocaleDateString('es-AR')
    }
  });
}

// -- Ordenar por score de calidad (rating x log de reseñas) --
results.sort((a, b) => {
  const scoreA = a.json.rating * Math.log(a.json.reseñas + 1);
  const scoreB = b.json.rating * Math.log(b.json.reseñas + 1);
  return scoreB - scoreA;
});

// -- Top 20 por categoria --
const topPorCategoria = {};
for (const r of results) {
  const cat = r.json.categoria;
  if (!topPorCategoria[cat]) topPorCategoria[cat] = [];
  if (topPorCategoria[cat].length < 20) topPorCategoria[cat].push(r);
}

return Object.values(topPorCategoria).flat();

